// Flat version for battles (backward compatible)
export const SAMPLE_QUESTIONS_BY_SUBJECT: Record<string, Array<{ q: string; options: string[]; correct: string }>> = Object.fromEntries(
  Object.entries(QUESTIONS_BY_SUBJECT_GRADE).map(([subject, grades]) => [
    subject,
    Object.values(grades).flat().map(({ q, options, correct }) => ({ q, options, correct })),
  ])
);

// Helper to get questions for a specific subject and grade
export function getQuestions(subject: string, grade: string, count?: number): QuestionItem[] {
  const subjectQuestions = QUESTIONS_BY_SUBJECT_GRADE[subject];
  if (!subjectQuestions) return [];
  const gradeQuestions = subjectQuestions[grade] || Object.values(subjectQuestions).flat();
  if (count) {
    const shuffled = [...gradeQuestions].sort(() => Math.random() - 0.5);
    return shuffled.slice(0, count);
  }
  return gradeQuestions;
}

// Get random questions for 30s challenge
export function getRandomQuestions(subject: string, count: number): QuestionItem[] {
  const all = SAMPLE_QUESTIONS_BY_SUBJECT[subject] || [];
  const shuffled = [...all].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count).map(q => ({ ...q, explanation: "", difficulty: "medium" as const }));
}
